+fn candidate(name: &str, domain: &str) -> StewardCandidate {
+    StewardCandidate::new(NodeId::new(name), domain)
+        .with_role(NodeRole::Steward)
+        .with_role(NodeRole::RepairWitness)
+        .with_storage_class(StorageClass::Durable)
+}
