+    let mut summary = summary
+        .lock()
+        .expect("summary lock")
+        .clone()
+        .expect("stream summary");
+    let mut log_entries = log.lock().expect("log lock").clone();
+    log_entries.sort_unstable_by_key(|entry| entry.seq);
+    summary.log = log_entries;
+    summary.steps = runtime.steps();
+    summary
+}
